// entry.S needs one stack per CPU.
__attribute__((aligned(16))) char stack0[4096 * NCPU];

// entry.S jumps here in supervisor mode on stack0.
// OpenSBI has already set up: M-mode exception delegation,
// PMP, and Sstc (stimecmp) for S-mode use.
void
start()
{
  // hartid was saved to tp by entry.S

  // enable supervisor external and timer interrupts.
  w_sie(r_sie() | SIE_SEIE | SIE_STIE);

  // ask for clock interrupts (Sstc already enabled by OpenSBI).
  timerinit();

  // switch to main() — we are already in supervisor mode.
  main();
}

// ask each hart to generate timer interrupts.
// OpenSBI has already enabled the Sstc extension and
// allowed supervisor to use stimecmp and time.
void
timerinit()
{
  // ask for the very first timer interrupt.
  w_stimecmp(r_time() + 1000000);
}

