int linux_dispatch(int num, uint64 *ret) {
  int lo = 0, hi = LSYSCNT - 1;
  while (lo <= hi) {
    int mid = (lo + hi) / 2;
    if (lsystab[mid].num == num) {
      *ret = lsystab[mid].fn();
      return 0;
    }
    if (lsystab[mid].num < num) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

