  uint16 max_mnt_count;      // 54
  uint16 magic;              // 56: 0xEF53
  uint16 state;              // 58
  uint16 errors;             // 60
  uint16 minor_rev_level;    // 62
  // ... more fields follow
  uint32 rev_level;          // 76
  uint16 inode_size;         // 88
  uint16 bg_desc_size;       // 90
  // Padding to make sb read at correct offset
} __attribute__((packed));

// Block Group Descriptor
struct ext4_bg_desc {
  uint32 block_bitmap_lo;
  uint32 inode_bitmap_lo;
  uint32 inode_table_lo;
  uint16 free_blocks_count_lo;
  uint16 free_inodes_count_lo;
  uint16 used_dirs_count_lo;
  uint16 flags;
  uint32 exclude_bitmap_lo;
  uint16 block_bitmap_csum_lo;
  uint16 inode_bitmap_csum_lo;
  uint16 itable_unused_lo;
  uint16 checksum;
} __attribute__((packed));

// EXT4 inode structure (simplified, 256 bytes in modern EXT4)
struct ext4_inode {
  uint16 mode;         // 0
  uint16 uid;          // 2
  uint32 size_lo;      // 4
  uint32 atime;        // 8
  uint32 ctime;        // 12
  uint32 mtime;        // 16
  uint32 dtime;        // 20
  uint16 gid;          // 24
  uint16 links_count;  // 26
  uint32 blocks_lo;    // 28: sector count
  uint32 flags;        // 32
  uint32 osd1;         // 36
  uint8  block_data[60]; // 40: extent tree or block pointers
  uint32 generation;   // 100
  uint32 file_acl_lo;  // 104
  uint32 size_high;    // 108
  uint32 obso_faddr;   // 112
  // ... osd2 (Linux fields) ...
  uint16 uid_high;     // at offset 120
  uint16 gid_high;     // at offset 122
  uint32 csum;         // at offset 140 (for metadata_csum)
} __attribute__((packed));

// EXT4 extent header
struct ext4_extent_header {
  uint16 magic;        // 0xF30A
  uint16 entries;      // number of valid entries
  uint16 max;          // capacity
  uint16 depth;        // 0 = leaf node
  uint32 generation;
} __attribute__((packed));

// EXT4 extent index (internal node)
struct ext4_extent_idx {
  uint32 block;        // first logical block covered
  uint32 leaf_lo;      // low 32 bits of physical block
  uint16 leaf_hi;      // high 16 bits
  uint16 unused;
} __attribute__((packed));

// EXT4 extent (leaf node)
struct ext4_extent {
  uint32 block;        // first logical block
  uint16 len;          // number of blocks
  uint16 start_hi;     // high 16 bits of physical block
  uint32 start_lo;     // low 32 bits of physical block
} __attribute__((packed));

// EXT4 directory entry
struct ext4_dir_entry {
  uint32 inode;        // inode number
  uint16 rec_len;      // total entry size
  uint8  name_len;     // filename length
  uint8  file_type;    // file type (0=unknown, 1=regular, 2=directory)
  char   name[0];      // variable-length name
} __attribute__((packed));

#define EXT4_MAGIC        0xEF53
#define EXT4_EXTENT_MAGIC 0xF30A
#define EXT4_ROOT_INO     2
#define EXT4_INODE_SIZE   256

// Block size: 1024 << sb.log_block_size (usually 0 -> 1024, or 2 -> 4096)

// EXT4 disk operations
int  ext4_disk_init(uint64 used_base);
int  ext4_read_block(uint64 block_num, char *buf);

// EXT4 filesystem operations
int  ext4_init(void);
int  ext4_read_file(const char *path, char *buf, int maxlen);

// Virtio helpers
uint64 virtio_disk_get_base(void);

#endif

// Minimal read-only EXT4 filesystem driver

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "riscv.h"
#include "defs.h"
#include "spinlock.h"
#include "fs.h"
#include "ext4.h"

extern int ext4_disk_init(uint64 used_base);
extern int ext4_read_block(uint64 block_num, char *buf);

static struct ext4_superblock sb;
static uint32 block_size;
static uint32 inodes_per_group;
static uint32 inode_size;
static uint32 blocks_per_group;
static uint64 bg_desc_table_block;
static int ext4_mounted = 0;

// block_num is in filesystem blocks (size = block_size)
static int read_fs_block(uint64 block_num, char *buf) {
  // Convert FS blocks to 512-byte sectors
  uint32 sectors_per_block = block_size / 512;
  for (uint32 i = 0; i < sectors_per_block; i++) {
    if (ext4_read_block(block_num * sectors_per_block + i, buf + i * 512) < 0)
      return -1;
  }
  return 0;
}

// Read an inode from disk
static int read_inode(uint32 inum, struct ext4_inode *ino) {
  if (inum < 1) return -1;
  inum--;  // inode numbers start at 1

  uint32 group = inum / inodes_per_group;
  uint32 index = inum % inodes_per_group;

  // Read group descriptor to find inode table
  char bg_buf[BSIZE];
  if (read_fs_block(bg_desc_table_block + (group * 64) / block_size, bg_buf) < 0)
    return -1;

  struct ext4_bg_desc *bg = (struct ext4_bg_desc *)(bg_buf + (group * 64) % block_size);
  uint64 inode_table = (uint64)bg->inode_table_lo;

  // Read the inode from the inode table
  uint64 inode_block = inode_table + (index * inode_size) / block_size;
  uint32 inode_offset = (index * inode_size) % block_size;

  char ino_buf[4096];  // max block size
  if (read_fs_block(inode_block, ino_buf) < 0)
    return -1;

  memmove(ino, ino_buf + inode_offset, sizeof(struct ext4_inode));
  return 0;
}

// Walk extent tree to find physical block for a logical file block
static uint64 extent_lookup(struct ext4_inode *ino, uint32 lblock) {
  struct ext4_extent_header *eh = (struct ext4_extent_header *)ino->block_data;
  if (eh->magic != EXT4_EXTENT_MAGIC) return 0;

  if (eh->depth == 0) {
    // Leaf node: search extents
    struct ext4_extent *ext = (struct ext4_extent *)(eh + 1);
    for (int i = 0; i < eh->entries; i++) {
      if (lblock >= ext[i].block && lblock < ext[i].block + ext[i].len) {
        uint32 offset = lblock - ext[i].block;
        uint64 phys = ((uint64)ext[i].start_hi << 32) | ext[i].start_lo;
        return phys + offset;
      }
    }
  }
  // For depth > 0, we'd need to walk internal nodes (not needed for small files)
  return 0;
}

// Read data from a file given its inode
static int read_file_data(struct ext4_inode *ino, char *buf, uint32 offset, uint32 len) {
  uint64 file_size = ino->size_lo;
  if (offset >= file_size) return 0;
  if (offset + len > file_size) len = file_size - offset;

  uint32 bytes_read = 0;
  while (bytes_read < len) {
    uint32 lblock = (offset + bytes_read) / block_size;
    uint32 block_off = (offset + bytes_read) % block_size;
    uint64 pblock = extent_lookup(ino, lblock);
    if (!pblock) {
      // Try direct/indirect block pointers (for small/old ext4)
      if (lblock < 12) {
        // Direct blocks at offset 40 in inode
        uint32 *blocks = (uint32 *)(ino->block_data);
        pblock = blocks[lblock];
      }
      if (!pblock) return bytes_read;  // sparse file or error
    }

    char block_buf[4096];
    if (read_fs_block(pblock, block_buf) < 0) return bytes_read;

    uint32 to_copy = len - bytes_read;
    if (to_copy > block_size - block_off) to_copy = block_size - block_off;
    memmove(buf + bytes_read, block_buf + block_off, to_copy);
    bytes_read += to_copy;
  }
  return bytes_read;
}

// Find directory entry by name, return inode number
static uint32 dir_lookup(struct ext4_inode *dir_ino, const char *name) {
  uint64 size = dir_ino->size_lo;
  char *dir_buf = kalloc();
  if (!dir_buf) return 0;

  uint32 found = 0;
  for (uint32 off = 0; off < size; ) {
    if (read_file_data(dir_ino, dir_buf, off, block_size) <= 0) break;

    struct ext4_dir_entry *de = (struct ext4_dir_entry *)dir_buf;
    uint32 scanned = 0;
    while (scanned < block_size && off + scanned < size) {
      if (de->inode && de->name_len > 0) {
        if (strncmp(de->name, name, de->name_len) == 0 && name[de->name_len] == 0) {
          found = de->inode;
          goto done;
        }
      }
      if (de->rec_len == 0) break;
      scanned += de->rec_len;
      de = (struct ext4_dir_entry *)((char*)de + de->rec_len);
    }
    off += block_size;
  }
done:
  kfree(dir_buf);
  return found;
}

// EXT4 read file by path - simple path walking
int ext4_read_file(const char *path, char *buf, int maxlen) {
  if (!ext4_mounted) return -1;

  // Start at root
  struct ext4_inode ino;
  if (read_inode(EXT4_ROOT_INO, &ino) < 0) return -1;

  // Parse path components
  char component[128];
  const char *p = path;
  if (*p == '/') p++;

  while (*p) {
    // Extract next component
    int ci = 0;
    while (*p && *p != '/' && ci < sizeof(component) - 1)
      component[ci++] = *p++;
    component[ci] = 0;
    if (*p == '/') p++;

    if (ci == 0) continue;

    // Lookup in current directory
    uint32 child_ino_num = dir_lookup(&ino, component);
    if (!child_ino_num) return -1;

    if (read_inode(child_ino_num, &ino) < 0) return -1;

    // If this is a directory, continue; if file, stop
    if (*p == 0) {
      // Read file data
      return read_file_data(&ino, buf, 0, maxlen);
    }
  }

  // If path is "/" or empty, list root directory
  return read_file_data(&ino, buf, 0, maxlen);
}

// Initialize EXT4 filesystem
int ext4_init(void) {
  // Read superblock at byte offset 1024 = xv6 block 1 (1024 bytes/block)
  // ext4_read_block takes xv6 block numbers (1024 bytes each)
  char sb_buf[1024];
  if (ext4_read_block(1, sb_buf) < 0) {
    printf("ext4: failed to read superblock\n");
    return -1;
  }

  // Superblock is at offset 1024 in block 0 (if block_size=1024)
  // Actually, superblock is at byte 1024, which is block 2 (512-byte sectors)
  struct ext4_superblock *sbp = (struct ext4_superblock *)sb_buf;
  if (sbp->magic != EXT4_MAGIC) {
    printf("ext4: bad magic 0x%x\n", sbp->magic);
    return -1;
  }

  memmove(&sb, sbp, sizeof(sb));
  block_size = 1024 << sb.log_block_size;
  inodes_per_group = sb.inodes_per_group;
  inode_size = sb.inode_size ? sb.inode_size : 128;
  blocks_per_group = sb.blocks_per_group;

  // Block group descriptor table starts at first block after superblock
  // For block_size=1024, it's at block 2; for block_size=4096, it's at block 1
  bg_desc_table_block = (block_size == 1024) ? 2 : 1;

  ext4_mounted = 1;
  printf("ext4: mounted, block_size=%d, inodes=%d\n", block_size, sb.inodes_count);
  return 0;
}

// Minimal EXT4 disk block reader using second virtio device
// This accesses bus.0 (the test disk) while xv6 uses bus.1

#include "types.h"
#include "riscv.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "virtio.h"

// Separate virtio disk for EXT4 (uses a different MMIO base than xv6)
static uint64 ext4_mmio_base;
static int ext4_ready = 0;

// The virtio MMIO registers
#define R(r) ((volatile uint32 *)(ext4_mmio_base + (r)))

static struct {
  struct virtq_desc *desc;
  struct virtq_avail *avail;
  struct virtq_used *used;
  char free[NUM];
  uint16 used_idx;
  struct { char status; } info[NUM];
  struct virtio_blk_req ops[NUM];
  struct spinlock lock;
} ext4_disk;

// Probe for virtio block device at a specific MMIO address
static int probe_ext4_virtio(uint64 base) {
  volatile uint32 *magic = (volatile uint32 *)(base + VIRTIO_MMIO_MAGIC_VALUE);
  volatile uint32 *version = (volatile uint32 *)(base + VIRTIO_MMIO_VERSION);
  volatile uint32 *devid = (volatile uint32 *)(base + VIRTIO_MMIO_DEVICE_ID);
  if (*magic != 0x74726976) return 0;
  if (*version != 1 && *version != 2) return 0;
  if (*devid != 2) return 0;
  return 1;
}

// Initialize EXT4 disk on the bus NOT used by xv6
int ext4_disk_init(uint64 used_base) {
  uint64 bases[] = {VIRTIO0, VIRTIO1};
  uint64 target = 0;

  for (int i = 0; i < 2; i++) {
    if (bases[i] != used_base && probe_ext4_virtio(bases[i])) {
      target = bases[i];
      break;
    }
  }
  if (!target) return -1;

  ext4_mmio_base = target;
  initlock(&ext4_disk.lock, "ext4_disk");

  uint32 status = 0;
  *R(VIRTIO_MMIO_STATUS) = status;
  status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
  *R(VIRTIO_MMIO_STATUS) = status;
  status |= VIRTIO_CONFIG_S_DRIVER;
  *R(VIRTIO_MMIO_STATUS) = status;

  uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
  features &= ~(1 << VIRTIO_BLK_F_RO);
  features &= ~(1 << VIRTIO_BLK_F_SCSI);
  features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
  features &= ~(1 << VIRTIO_BLK_F_MQ);
  features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
  features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
  features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
  *R(VIRTIO_MMIO_DRIVER_FEATURES) = (uint32)features;

  status |= VIRTIO_CONFIG_S_FEATURES_OK;
  *R(VIRTIO_MMIO_STATUS) = status;
  if (!(*R(VIRTIO_MMIO_STATUS) & VIRTIO_CONFIG_S_FEATURES_OK))
    return -1;

  *R(VIRTIO_MMIO_QUEUE_SEL) = 0;
  if (*R(VIRTIO_MMIO_QUEUE_READY)) return -1;
  if (*R(VIRTIO_MMIO_QUEUE_NUM_MAX) < NUM) return -1;

  ext4_disk.desc = kalloc();
  ext4_disk.avail = kalloc();
  ext4_disk.used = kalloc();
  if (!ext4_disk.desc || !ext4_disk.avail || !ext4_disk.used)
    return -1;
  memset(ext4_disk.desc, 0, PGSIZE);
  memset(ext4_disk.avail, 0, PGSIZE);
  memset(ext4_disk.used, 0, PGSIZE);

  *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
  *R(VIRTIO_MMIO_QUEUE_DESC_LOW) = (uint64)ext4_disk.desc;
  *R(VIRTIO_MMIO_QUEUE_DESC_HIGH) = (uint64)ext4_disk.desc >> 32;
  *R(VIRTIO_MMIO_DRIVER_DESC_LOW) = (uint64)ext4_disk.avail;
  *R(VIRTIO_MMIO_DRIVER_DESC_HIGH) = (uint64)ext4_disk.avail >> 32;
  *R(VIRTIO_MMIO_DEVICE_DESC_LOW) = (uint64)ext4_disk.used;
  *R(VIRTIO_MMIO_DEVICE_DESC_HIGH) = (uint64)ext4_disk.used >> 32;
  *R(VIRTIO_MMIO_QUEUE_READY) = 1;

  for (int i = 0; i < NUM; i++) ext4_disk.free[i] = 1;

  status |= VIRTIO_CONFIG_S_DRIVER_OK;
  *R(VIRTIO_MMIO_STATUS) = status;
  ext4_ready = 1;
  printf("ext4: disk found at 0x%lx\n", target);
  return 0;
}

// Allocate a single descriptor
static int ext4_alloc_desc() {
  for (int i = 0; i < NUM; i++) {
    if (ext4_disk.free[i]) { ext4_disk.free[i] = 0; return i; }
  }
  return -1;
}

// Free a chain of descriptors
static void ext4_free_chain(int idx) {
  while (1) {
    int flag = ext4_disk.desc[idx].flags;
    int nxt = ext4_disk.desc[idx].next;
    ext4_disk.desc[idx].addr = 0;
    ext4_disk.desc[idx].len = 0;
    ext4_disk.desc[idx].flags = 0;
    ext4_disk.desc[idx].next = 0;
    ext4_disk.free[idx] = 1;
    if (flag & VRING_DESC_F_NEXT) idx = nxt;
    else break;
  }
}

// Read a block from EXT4 disk
int ext4_read_block(uint64 block_num, char *buf) {
  if (!ext4_ready) return -1;

  acquire(&ext4_disk.lock);

  int idx[3];
  while (1) {
    for (int i = 0; i < 3; i++) {
      idx[i] = ext4_alloc_desc();
      if (idx[i] < 0) {
        for (int j = 0; j < i; j++) ext4_disk.free[idx[j]] = 1;
        sleep(&ext4_disk.free[0], &ext4_disk.lock);
        goto retry;
      }
    }
    break;
retry:;
  }

  struct virtio_blk_req *req = &ext4_disk.ops[idx[0]];
  req->type = VIRTIO_BLK_T_IN;
  req->reserved = 0;
  req->sector = block_num * (BSIZE / 512);

  ext4_disk.desc[idx[0]].addr = (uint64)req;
  ext4_disk.desc[idx[0]].len = sizeof(struct virtio_blk_req);
  ext4_disk.desc[idx[0]].flags = VRING_DESC_F_NEXT;
  ext4_disk.desc[idx[0]].next = idx[1];

  ext4_disk.desc[idx[1]].addr = (uint64)buf;
  ext4_disk.desc[idx[1]].len = BSIZE;
  ext4_disk.desc[idx[1]].flags = VRING_DESC_F_WRITE;
  ext4_disk.desc[idx[1]].flags |= VRING_DESC_F_NEXT;
  ext4_disk.desc[idx[1]].next = idx[2];

  ext4_disk.info[idx[0]].status = 0xff;
  ext4_disk.desc[idx[2]].addr = (uint64)&ext4_disk.info[idx[0]].status;
  ext4_disk.desc[idx[2]].len = 1;
  ext4_disk.desc[idx[2]].flags = VRING_DESC_F_WRITE;
  ext4_disk.desc[idx[2]].next = 0;

  ext4_disk.avail->ring[ext4_disk.avail->idx % NUM] = idx[0];
  __atomic_thread_fence(__ATOMIC_SEQ_CST);
  ext4_disk.avail->idx += 1;
  __atomic_thread_fence(__ATOMIC_SEQ_CST);
  *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0;

  // Poll for completion (no interrupt needed for simple reads)
  while (ext4_disk.info[idx[0]].status == 0xff) {
    // Check used ring
    if (ext4_disk.used_idx != ext4_disk.used->idx) {
      __atomic_thread_fence(__ATOMIC_SEQ_CST);
      ext4_disk.used_idx = ext4_disk.used->idx;
      ext4_disk.info[idx[0]].status = 0;
    }
  }

  ext4_free_chain(idx[0]);
  release(&ext4_disk.lock);
  return 0;
}

// File system implementation.  Five layers:
//   + Blocks: allocator for raw disk blocks.
//   + Log: crash recovery for multi-step updates.
//   + Files: inode allocator, reading, writing, metadata.
//   + Directories: inode with special contents (list of other inodes!)
//   + Names: paths like /usr/rtm/xv6/fs.c for convenient naming.
//
// This file contains the low-level file system manipulation
// routines.  The (higher-level) system call implementations
// are in sysfile.c.

#include "types.h"
#include "riscv.h"
#include "defs.h"
#include "param.h"
#include "stat.h"
#include "spinlock.h"
#include "proc.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "file.h"

#define min(a, b) ((a) < (b) ? (a) : (b))
// there should be one superblock per disk device, but we run with
// only one device
struct superblock sb;

// Read the super block.
static void
readsb(int dev, struct superblock *sb)
{
  struct buf *bp;

  bp = bread(dev, 1);
  memmove(sb, bp->data, sizeof(*sb));
  brelse(bp);
}

// Init fs
void
fsinit(int dev)
{
  readsb(dev, &sb);
  if (sb.magic != FSMAGIC)
    panic("invalid file system");
  initlog(dev, &sb);
  ireclaim(dev);
}

// Zero a block.
static void
bzero(int dev, int bno)
{
  struct buf *bp;

  bp = bread(dev, bno);
  memset(bp->data, 0, BSIZE);
  log_write(bp);
  brelse(bp);
}

// Blocks.

// Allocate a zeroed disk block.
// returns 0 if out of disk space.
static uint
balloc(uint dev)
{
  int b, bi, m;
  struct buf *bp;

  bp = 0;
  for (b = 0; b < sb.size; b += BPB) {
    bp = bread(dev, BBLOCK(b, sb));
    for (bi = 0; bi < BPB && b + bi < sb.size; bi++) {
      m = 1 << (bi % 8);
      if ((bp->data[bi / 8] & m) == 0) { // Is block free?
        bp->data[bi / 8] |= m;           // Mark block in use.
        log_write(bp);
        brelse(bp);
        bzero(dev, b + bi);
        return b + bi;
      }
    }
    brelse(bp);
  }
  printf("balloc: out of blocks\n");
  return 0;
}

// Free a disk block.
static void
bfree(int dev, uint b)
{
  struct buf *bp;
  int bi, m;

  bp = bread(dev, BBLOCK(b, sb));
  bi = b % BPB;
  m = 1 << (bi % 8);
  if ((bp->data[bi / 8] & m) == 0)
    panic("freeing free block");
  bp->data[bi / 8] &= ~m;
  log_write(bp);
  brelse(bp);
}

// Inodes.
//
// An inode describes a single unnamed file.
// The inode disk structure holds metadata: the file's type,
// its size, the number of links referring to it, and the
// list of blocks holding the file's content.
//
// The inodes are laid out sequentially on disk at block
// sb.inodestart. Each inode has a number, indicating its
// position on the disk.
//
// The kernel keeps a table of in-use inodes in memory
// to provide a place for synchronizing access
// to inodes used by multiple processes. The in-memory
// inodes include book-keeping information that is
// not stored on disk: ip->ref and ip->valid.
//
// An inode and its in-memory representation go through a
// sequence of states before they can be used by the
// rest of the file system code.
//
// * Allocation: an inode is allocated if its type (on disk)
//   is non-zero. ialloc() allocates, and iput() frees if
//   the reference and link counts have fallen to zero.
//
// * Referencing in table: an entry in the inode table
//   is free if ip->ref is zero. Otherwise ip->ref tracks
//   the number of in-memory pointers to the entry (open
//   files and current directories). iget() finds or
//   creates a table entry and increments its ref; iput()
//   decrements ref.
//
// * Valid: the information (type, size, &c) in an inode
//   table entry is only correct when ip->valid is 1.
//   ilock() reads the inode from
//   the disk and sets ip->valid, while iput() clears
//   ip->valid if ip->ref has fallen to zero.
//
// * Locked: file system code may only examine and modify
//   the information in an inode and its content if it
//   has first locked the inode.
//
// Thus a typical sequence is:
//   ip = iget(dev, inum)
//   ilock(ip)
//   ... examine and modify ip->xxx ...
//   iunlock(ip)
//   iput(ip)
//
// ilock() is separate from iget() so that system calls can
// get a long-term reference to an inode (as for an open file)
// and only lock it for short periods (e.g., in read()).
// The separation also helps avoid deadlock and races during
// pathname lookup. iget() increments ip->ref so that the inode
// stays in the table and pointers to it remain valid.
//
// Many internal file system functions expect the caller to
// have locked the inodes involved; this lets callers create
// multi-step atomic operations.
//
// The itable.lock spin-lock protects the allocation of itable
