sys_fork(void)
{
  return kfork();
}

uint64
sys_wait(void)
{
  uint64 p;
  argaddr(0, &p);
  return kwait(p);
}

uint64
sys_sbrk(void)
{
  uint64 addr;
  int t;
  int n;

  argint(0, &n);
  argint(1, &t);
  addr = myproc()->sz;

  if (t == SBRK_EAGER || n < 0) {
    if (growproc(n) < 0) {
      return -1;
    }
  } else {
    // Lazily allocate memory for this process: increase its memory
    // size but don't allocate memory. If the processes uses the
    // memory, vmfault() will allocate it.
    if (addr + n < addr)
      return -1;
    if (addr + n > TRAPFRAME)
      return -1;
    myproc()->sz += n;
  }
  return addr;
}

uint64
sys_pause(void)
{
  int n;
  uint ticks0;

  argint(0, &n);
  if (n < 0)
    n = 0;
  acquire(&tickslock);
  ticks0 = ticks;
  while (ticks - ticks0 < n) {
    if (killed(myproc())) {
      release(&tickslock);
      return -1;
    }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);
  return 0;
}

uint64
sys_kill(void)
{
  int pid;

  argint(0, &pid);
  return kkill(pid);
}

// return how many clock tick interrupts have occurred
// since start.
uint64
sys_uptime(void)
{
  uint xticks;

  acquire(&tickslock);
  xticks = ticks;
  release(&tickslock);
  return xticks;
}

// SBI shutdown - uses SBI SRST extension
uint64
sys_shutdown(void)
{
  // SBI shutdown via SRST extension
  // a7 = 0x53525354 (SBI_EXT_SRST), a6 = 0 (reset), a0 = 0 (shutdown), a1 = 0 (no reason)
  register uint64 a7 asm("a7") = 0x53525354;
  register uint64 a6 asm("a6") = 0;
  register uint64 a0 asm("a0") = 0;
  register uint64 a1 asm("a1") = 0;
  asm volatile("ecall" : : "r"(a7), "r"(a6), "r"(a0), "r"(a1));
  return 0;
}

// Debug: print string directly to UART from kernel space
uint64 sys_kputs(void) {
  uint64 addr;
  argaddr(0, &addr);
  char buf[256];
  if (fetchstr(addr, buf, sizeof(buf)) > 0) {
    for (char *p = buf; *p; p++) consputc(*p);
  }
  return 0;
}

